const pipelineJobContext = new AsyncLocalStorage<{ jobId: string }>()
const canceledPipelineJobIds = new Set<string>()
const ffmpegProcessesByJobId = new Map<string, Set<ReturnType<typeof spawn>>>()

class JobCanceledError extends Error {
  jobId?: string
  constructor(jobId?: string) {
    super('job_canceled')
    this.name = 'JobCanceledError'
    this.jobId = jobId
  }
}

class HookGateError extends Error {
  reason: string
  details: any
  constructor(reason: string, details?: any) {
    super('FAILED_HOOK')
    this.name = 'HookGateError'
    this.reason = reason
    this.details = details ?? null
  }
}

class QualityGateError extends Error {
  reason: string
  details: any
  constructor(reason: string, details?: any) {
    super('FAILED_QUALITY_GATE')
    this.name = 'QualityGateError'
    this.reason = reason
    this.details = details ?? null
  }
}

const getPipelineJobId = () => pipelineJobContext.getStore()?.jobId

const isPipelineCanceled = (jobId?: string | null) => {
  if (!jobId) return false
  return canceledPipelineJobIds.has(jobId)
}

const markPipelineCanceled = (jobId: string) => {
  if (!jobId) return
  canceledPipelineJobIds.add(jobId)
}

const clearPipelineCanceled = (jobId: string) => {
  if (!jobId) return
  canceledPipelineJobIds.delete(jobId)
}

const killJobFfmpegProcesses = (jobId: string) => {
  const processes = ffmpegProcessesByJobId.get(jobId)
  if (!processes || processes.size === 0) return 0
  let killed = 0
  for (const proc of Array.from(processes)) {
    if (!proc || proc.killed) continue
    try {
      proc.kill('SIGKILL')
      killed += 1
    } catch (e) {
      // ignore
    }
  }
  return killed
}

const runFfmpegProcess = (args: string[]) => {
  return new Promise<FfmpegRunResult>((resolve, reject) => {
    const proc = spawn(FFMPEG_PATH, args, { stdio: 'pipe' })
    const jobId = getPipelineJobId()
    if (jobId) {
      let set = ffmpegProcessesByJobId.get(jobId)
      if (!set) {
        set = new Set()
        ffmpegProcessesByJobId.set(jobId, set)
      }
      set.add(proc)
      if (isPipelineCanceled(jobId)) {
        try {
          proc.kill('SIGKILL')
        } catch (e) {
          // ignore
        }
      }
    }
    let stdout = ''
    let stderr = ''
    let finished = false
    const cleanup = () => {
      if (finished) return
      finished = true
      if (!jobId) return
      const set = ffmpegProcessesByJobId.get(jobId)
      if (!set) return
      set.delete(proc)
      if (set.size === 0) ffmpegProcessesByJobId.delete(jobId)
    }
    proc.stdout.on('data', (data) => {
      if (stdout.length >= FFMPEG_LOG_LIMIT) return
      stdout += data.toString()
    })
    proc.stderr.on('data', (data) => {
      if (stderr.length >= FFMPEG_LOG_LIMIT) return
      stderr += data.toString()
    })
    proc.on('error', (err) => {
      cleanup()
      const wrapped: any = new Error(`ffmpeg_spawn_error:${String((err as any)?.code || err?.message || 'unknown')}`)
      wrapped.cause = err
      wrapped.command = formatFfmpegCommand(args)
      wrapped.stdout = stdout
      wrapped.stderr = stderr
      reject(wrapped)
    })
    proc.on('close', (exitCode, signal) => {
      cleanup()
      resolve({ exitCode, signal, stdout, stderr })
    })
  })
}

const runFfmpeg = async (args: string[]) => {
  const jobId = getPipelineJobId()
  if (isPipelineCanceled(jobId)) {
    throw new JobCanceledError(jobId || undefined)
  }
  const result = await runFfmpegProcess(args)
  if (result.exitCode === 0) {
    if (isPipelineCanceled(jobId)) throw new JobCanceledError(jobId || undefined)
    return result
  }
  if (isPipelineCanceled(jobId)) {
    throw new JobCanceledError(jobId || undefined)
  }
  const errorCode = result.exitCode === null || result.exitCode === undefined
    ? (result.signal ? `signal_${result.signal}` : 'unknown')
    : String(result.exitCode)
  const err: any = new Error(`ffmpeg_failed_${errorCode}`)
  err.exitCode = result.exitCode
  err.exitSignal = result.signal
  err.stdout = result.stdout
  err.stderr = result.stderr
  err.command = formatFfmpegCommand(args)
  throw err
}

const escapeFfmpegDrawtextText = (value: string) => (
  String(value || '')
    .replace(/\\/g, '\\\\')
    .replace(/:/g, '\\:')
    .replace(/'/g, "\\'")
    .replace(/\[/g, '\\[')
    .replace(/\]/g, '\\]')
    .replace(/%/g, '\\%')
)

const executeFFmpegPlan = async (input: string, plan: EditPlan, options: any) => {
  const safePlan: Partial<EditPlan> & Record<string, any> = (
    plan && typeof plan === 'object'
      ? (plan as Partial<EditPlan> & Record<string, any>)
      : { segments: [] }
  )
  const outputPath = String(
    options?.outputPath ||
    path.join(os.tmpdir(), `ffmpeg-plan-${Date.now()}-${crypto.randomUUID().slice(0, 8)}.mp4`)
  )
  const fps = Number.isFinite(Number(options?.fps)) ? Math.max(1, Number(options.fps)) : 25
  const preset = String(options?.preset || 'slow')
  const crf = String(options?.crf || '23')
  const sfxInputs = Array.isArray(options?.sfxInputs)
    ? options.sfxInputs.map((entry: any) => String(entry || '').trim()).filter(Boolean)
    : []
  const sfxVolume = Number.isFinite(Number(options?.sfxVolume))
    ? clamp(Number(options.sfxVolume), 0, 2)
    : 0.75

  const rawCuts = Array.isArray((safePlan as any)?.cuts) && (safePlan as any).cuts.length
    ? (safePlan as any).cuts
    : (safePlan.segments || []).map((segment, index) => ({
      id: index,
      start: segment.start,
      end: segment.end
    }))
  const normalizedCuts = rawCuts
    .map((cut: any, index: number) => {
      const start = Number(cut?.start)
      const end = Number(cut?.end)
      if (!Number.isFinite(start) || !Number.isFinite(end) || end - start <= 0.05) return null
      return {
        id: Number.isFinite(Number(cut?.id)) ? Number(cut.id) : index,
        start: Number(start.toFixed(3)),
        end: Number(end.toFixed(3)),
        duration: Number((end - start).toFixed(3))
      }
    })
    .filter((cut: any) => Boolean(cut))

  const rawZooms = Array.isArray((safePlan as any)?.zooms) ? (safePlan as any).zooms : []
  const normalizedZooms = rawZooms
    .map((zoom: any, index: number) => {
      const intensity = Number.isFinite(Number(zoom?.intensity)) ? clamp(Number(zoom.intensity), 0, 3) : 0
      const duration = Number.isFinite(Number(zoom?.duration)) ? Math.max(0.08, Number(zoom.duration)) : 0
      const inputId = Number.isFinite(Number(zoom?.inputId)) ? Number(zoom.inputId) : null
      if (!intensity || !duration) return null
      return {
        id: Number.isFinite(Number(zoom?.id)) ? Number(zoom.id) : index,
        inputId,
        intensity,
        duration
      }
    })
    .filter((zoom: any) => Boolean(zoom))

  const rawCaptions = Array.isArray((safePlan as any)?.captions) ? (safePlan as any).captions : []
  const normalizedCaptions = rawCaptions
    .map((caption: any) => {
      const text = String(caption?.text || '').trim()
      const start = Number(caption?.start)
      const end = Number(caption?.end)
      if (!text || !Number.isFinite(start) || !Number.isFinite(end) || end - start <= 0.05) return null
      return {
        text,
        start: Number(start.toFixed(3)),
        end: Number(end.toFixed(3))
      }
    })
    .filter((caption: any) => Boolean(caption))

  const filterComplex: string[] = []
  let currentVideoLabel = '0:v'
  let hasVideoFilter = false

  if (normalizedCuts.length > 0) {
    normalizedCuts.forEach((cut: { id: number; start: number; end: number }) => {
      filterComplex.push(
        `[0:v]trim=start=${toFilterNumber(cut.start)}:end=${toFilterNumber(cut.end)},setpts=PTS-STARTPTS[vcut${cut.id}]`
      )
    })
    const concatInputs = normalizedCuts.map((cut: { id: number }) => `[vcut${cut.id}]`).join('')
    filterComplex.push(`${concatInputs}concat=n=${normalizedCuts.length}:v=1:a=0[vcuts]`)
    currentVideoLabel = 'vcuts'
    hasVideoFilter = true
  }

  normalizedZooms.forEach((zoom: { id: number; inputId: number | null; intensity: number; duration: number }, index: number) => {
    const sourceLabel = zoom.inputId !== null
      ? `vcut${zoom.inputId}`
      : currentVideoLabel
    const availableInput = hasVideoFilter ? `[${sourceLabel}]` : '[0:v]'
    const zoomLabel = `vzoom${zoom.id}`
    const frameCount = Math.max(1, Math.round(zoom.duration * fps))
    filterComplex.push(
      `${availableInput}zoompan=z='zoom+0.001*${toFilterNumber(zoom.intensity)}':d=${frameCount}:x='iw/2-(iw/zoom/2)':y='ih/2-(ih/zoom/2)'[${zoomLabel}]`
    )
    currentVideoLabel = zoomLabel
    hasVideoFilter = true
  })

  normalizedCaptions.forEach((caption: { text: string; start: number; end: number }, index: number) => {
    const sourceLabel = hasVideoFilter ? `[${currentVideoLabel}]` : '[0:v]'
    const outLabel = `vcap${index}`
    const escapedText = escapeFfmpegDrawtextText(caption.text)
    filterComplex.push(
      `${sourceLabel}drawtext=text='${escapedText}':fontfile=KomikaAxis.ttf:fontsize=120:fontcolor=yellow@1.0:borderw=16:bordercolor=black:x=(w-tw)/2:y=h-th-100:enable='between(t,${toFilterNumber(caption.start)},${toFilterNumber(caption.end)})':alpha='if(lt(t-${toFilterNumber(caption.start)},0.3),(t-${toFilterNumber(caption.start)})/0.3,1)'[${outLabel}]`
    )
    currentVideoLabel = outLabel
    hasVideoFilter = true
  })

  let audioMap = '0:a?'
  if (sfxInputs.length > 0) {
    filterComplex.push('[0:a]aformat=sample_rates=48000:channel_layouts=stereo[abase]')
    const mixInputs = ['[abase]']
    sfxInputs.forEach((_, index) => {
      const sfxLabel = `asfx${index}`
      filterComplex.push(
        `[${index + 1}:a]aformat=sample_rates=48000:channel_layouts=stereo,volume=${toFilterNumber(sfxVolume)}[${sfxLabel}]`
      )
      mixInputs.push(`[${sfxLabel}]`)
    })
    filterComplex.push(
      `${mixInputs.join('')}amix=inputs=${mixInputs.length}:dropout_transition=0:normalize=0[aout]`
    )
    audioMap = '[aout]'
  }

  const command = [
    '-y',
    '-nostdin',
    '-hide_banner',
    '-loglevel',
    'error',
    '-i',
    input,
    ...sfxInputs.flatMap((entry) => ['-i', entry]),
    '-movflags',
    '+faststart'
  ]
  if (filterComplex.length) {
    command.push('-filter_complex', filterComplex.join(';'))
  }
  command.push('-map', hasVideoFilter ? `[${currentVideoLabel}]` : '0:v')
  command.push('-map', audioMap)
  command.push(
    '-c:v',
    'libx264',
    '-preset',
    preset,
    '-crf',
    crf,
    '-pix_fmt',
    'yuv420p',
    '-c:a',
    'aac',
    '-b:a',
    String(options?.audioBitrate || '160k'),
    outputPath
  )
  await runFfmpeg(command)
  return outputPath
}

const formatFfmpegCommand = (args: string[]) => {
  return formatCommand(FFMPEG_PATH, args)
}

const formatFfmpegFailure = (err: any) => {
  const message = err?.message ? String(err.message) : 'ffmpeg_failed'
  const stderr = err?.stderr ? String(err.stderr).trim() : ''
  const stdout = err?.stdout ? String(err.stdout).trim() : ''
  const hasFfmpegContext =
    err?.exitCode !== undefined ||
    err?.exitSignal !== undefined ||
    Boolean(stderr) ||
    Boolean(stdout) ||
    /^ffmpeg_/i.test(message) ||
    String(err?.command || '').toLowerCase().includes('ffmpeg')
  const detail = [stderr, stdout].filter(Boolean).join('\n')
  const exitDetail = err?.exitCode !== undefined && err?.exitCode !== null
    ? `exit=${err.exitCode}`
    : (err?.exitSignal ? `signal=${err.exitSignal}` : 'exit=unknown')
  const combined = hasFfmpegContext
    ? `${message} (${exitDetail})${detail ? `\n${detail}` : ''}`
    : `${message}${detail ? `\n${detail}` : ''}`
  return combined.length > 3500 ? combined.slice(0, 3500) : combined
}

const safeUnlink = (filePath?: string | null) => {
  if (!filePath) return
  try {
    if (fs.existsSync(filePath)) fs.unlinkSync(filePath)
  } catch (e) {
    // ignore
  }
}

export const updateJob = async (
  jobId: string,
  data: any,
  opts?: {
    expectedUpdatedAt?: Date | string | null
  }
) => {
  const nextData = data && typeof data === 'object' ? { ...data } : {}
  const hasStatusPatch = Object.prototype.hasOwnProperty.call(nextData, 'status')
  const hasAnalysisPatch = Object.prototype.hasOwnProperty.call(nextData, 'analysis')
  let expectedUpdatedAt: Date | null = null

  if (opts?.expectedUpdatedAt) {
    const parsedExpected = new Date(opts.expectedUpdatedAt)
    if (Number.isFinite(parsedExpected.getTime())) expectedUpdatedAt = parsedExpected
  }

  const normalizedStatus = hasStatusPatch ? normalizeJobStatus(nextData.status) : null
  if (hasStatusPatch && !normalizedStatus) {
    throw new Error(`invalid_job_status:${String(nextData.status || '')}`)
  }
  if (normalizedStatus) nextData.status = normalizedStatus

  if (hasAnalysisPatch && nextData.analysis !== null && nextData.analysis !== undefined) {
    nextData.analysis = normalizeAnalysisPayload(nextData.analysis)
  }

  if (normalizedStatus) {
    const maxStatusUpdateAttempts = 4
    for (let attempt = 1; attempt <= maxStatusUpdateAttempts; attempt += 1) {
      const existing = await prisma.job.findUnique({
        where: { id: jobId },
        select: { status: true }
      })
      if (!existing) throw new Error('job_not_found')
      const currentStatus = normalizeJobStatus(existing.status)
      if (!currentStatus) throw new Error(`invalid_job_status:${String(existing.status || '')}`)

      if (
        EDITOR_RETENTION_CONFIG.enforceStatusTransitions &&
        !isJobStatusTransitionAllowed(currentStatus, normalizedStatus)
      ) {
        const allowRecoveredCompletion =
          normalizedStatus === 'completed' &&
          (currentStatus === 'queued' || currentStatus === 'uploading') &&
          Number(nextData.progress ?? 0) >= 90 &&
          typeof nextData.outputPath === 'string' &&
          String(nextData.outputPath || '').trim().length > 0
        if (allowRecoveredCompletion) {
          console.warn(`[queue] allowing recovered completion transition ${currentStatus}->${normalizedStatus}`, {
            jobId,
            progress: Number(nextData.progress ?? 0)
          })
        } else if (isLikelyStaleJobStatusUpdate(currentStatus, normalizedStatus)) {
          const current = await prisma.job.findUnique({ where: { id: jobId } })
          if (!current) throw new Error('job_not_found')
          return current
        } else {
          throw new Error(`invalid_status_transition:${currentStatus}->${normalizedStatus}`)
        }
      }

      const statusWhere: Record<string, any> = { id: jobId, status: currentStatus }
      if (expectedUpdatedAt) statusWhere.updatedAt = expectedUpdatedAt
      const result = await prisma.job.updateMany({
        where: statusWhere as any,
        data: nextData
      })
      if (result.count > 0) {
        const updated = await prisma.job.findUnique({ where: { id: jobId } })
        if (!updated) throw new Error('job_not_found')
        broadcastJobUpdate(updated.userId, { job: updated })
        return updated
      }

      if (expectedUpdatedAt) {
        const conflict: any = new Error('job_update_conflict')
        conflict.code = 'job_update_conflict'
        throw conflict
      }

      const latest = await prisma.job.findUnique({
        where: { id: jobId },
        select: { status: true }
      })
      if (!latest) throw new Error('job_not_found')
      const latestStatus = normalizeJobStatus(latest.status)
      if (!latestStatus) {
        throw new Error(`invalid_job_status:${String(latest.status || '')}`)
      }
      if (
        latestStatus === normalizedStatus ||
        isLikelyStaleJobStatusUpdate(latestStatus, normalizedStatus)
      ) {
        const current = await prisma.job.findUnique({ where: { id: jobId } })
        if (!current) throw new Error('job_not_found')
        return current
      }

      if (attempt === maxStatusUpdateAttempts) {
        throw new Error('job_status_update_conflict')
      }
    }
  }

  let updated: any
  if (expectedUpdatedAt) {
    const result = await prisma.job.updateMany({
      where: { id: jobId, updatedAt: expectedUpdatedAt },
      data: nextData
    })
    if (result.count === 0) {
      const conflict: any = new Error('job_update_conflict')
      conflict.code = 'job_update_conflict'
      throw conflict
    }
    updated = await prisma.job.findUnique({ where: { id: jobId } })
    if (!updated) throw new Error('job_not_found')
  } else {
    updated = await prisma.job.update({ where: { id: jobId }, data: nextData })
  }

  broadcastJobUpdate(updated.userId, { job: updated })
  return updated
}

const getDurationSeconds = (filePath: string) => {
  try {
    if (hasFfprobe()) {
      const result = spawnSync(
        FFPROBE_PATH,
        ['-v', 'error', '-show_entries', 'format=duration', '-of', 'default=nk=1:nw=1', filePath],
        { encoding: 'utf8' }
      )
      if (result.status === 0) {
        const value = String(result.stdout || '').trim()
        const parsed = Number.parseFloat(value)
        if (Number.isFinite(parsed) && parsed > 0) return parsed
      }
    }
  } catch (e) {
    // ignore and fall back to ffmpeg
  }
  if (!hasFfmpeg()) return null
  try {
    const result = spawnSync(FFMPEG_PATH, ['-hide_banner', '-i', filePath], { encoding: 'utf8' })
    const output = `${result.stderr || ''}\n${result.stdout || ''}`
    const match = output.match(/Duration:\s*([0-9]+):([0-9]+):([0-9.]+)/)
    if (!match) return null
    const hours = Number.parseInt(match[1], 10)
    const minutes = Number.parseInt(match[2], 10)
    const seconds = Number.parseFloat(match[3])
    if (!Number.isFinite(hours) || !Number.isFinite(minutes) || !Number.isFinite(seconds)) return null
    const total = hours * 3600 + minutes * 60 + seconds
    return Number.isFinite(total) && total > 0 ? total : null
  } catch (e) {
    return null
  }
}

const toMinutes = (seconds?: number | null) => {
  if (!seconds || seconds <= 0) return 0
  return Math.ceil(seconds / 60)
}

const formatHookTimestamp = (seconds: number) => {
  const safe = Math.max(0, Number(seconds) || 0)
  const minutes = Math.floor(safe / 60)
  const secondsRemainder = safe - minutes * 60
  return `${String(minutes).padStart(2, '0')}:${secondsRemainder.toFixed(3).padStart(6, '0')}`
}

const formatHookRange = (start: number, end: number) => {
  const safeStart = Math.max(0, Number(start) || 0)
  const safeEnd = Math.max(safeStart, Number(end) || safeStart)
  return `${formatHookTimestamp(safeStart)}-${formatHookTimestamp(safeEnd)}`
}

const getTargetDimensions = (quality?: ExportQuality | null) => {
  if (quality === '4k') return { width: 3840, height: 2160 }
  if (quality === '1080p') return { width: 1920, height: 1080 }
  if (quality === '720p') return { width: 1280, height: 720 }
  return { width: 1280, height: 720 }
}

