const pickFirstDefinedValue = (...values: any[]) => {
  for (const value of values) {
    if (value !== undefined) return value
  }
  return undefined
}

const MAX_VERTICAL_CAPTION_WORDS = 5
const normalizeVerticalCaptionPhraseInput = (value: any): string => {
  const compact = String(value ?? '')
    .replace(/\s+/g, ' ')
    .trim()
    .slice(0, 84)
  if (!compact) return ''
  return compact
    .split(' ')
    .filter(Boolean)
    .slice(0, MAX_VERTICAL_CAPTION_WORDS)
    .join(' ')
}

const normalizeVerticalCaptionLineInput = (value: any): string =>
  String(value ?? '')
    .replace(/\s+/g, ' ')
    .trim()
    .slice(0, 240)

const normalizeVerticalCaptionTextInput = (value: any): string => {
  const normalized = String(value ?? '')
    .replace(/\r\n?/g, '\n')
    .replace(/[ \t]+\n/g, '\n')
    .replace(/\n{3,}/g, '\n\n')
    .split('\n')
    .map((line) => normalizeVerticalCaptionLineInput(line))
    .filter(Boolean)
    .slice(0, 18)
    .join('\n')
    .trim()
  if (!normalized) return ''
  return normalized.slice(0, 1_800)
}

const MAX_MANUAL_VERTICAL_CAPTION_LINES = 4
const MAX_MANUAL_VERTICAL_CAPTION_CHARS = 320
const isLikelyManualVerticalCaptionText = (value: string) => {
  const normalized = normalizeVerticalCaptionTextInput(value)
  if (!normalized) return false
  const lineCount = normalized.split(/\n+/).filter(Boolean).length
  return lineCount <= MAX_MANUAL_VERTICAL_CAPTION_LINES && normalized.length <= MAX_MANUAL_VERTICAL_CAPTION_CHARS
}

const parseVerticalCaptionPreset = (value: any): VerticalCaptionPreset | null => {
  const raw = String(value ?? '').trim().toLowerCase()
  if (!raw) return null
  const token = raw.split('::')[0].trim()
  const compact = token.replace(/\s+/g, '_')
  const aliases: Record<string, VerticalCaptionPreset> = {
    basic_clean: 'basic_clean',
    basic: 'basic_clean',
    clean: 'basic_clean',
    mrbeast_animated: 'mrbeast_animated',
    mrbeast: 'mrbeast_animated',
    beast: 'mrbeast_animated',
    viral_beast: 'mrbeast_animated',
    neon_glow: 'neon_glow',
    neon: 'neon_glow',
    bold_clean_box: 'bold_clean_box',
    solid_box: 'bold_clean_box',
    caption_box: 'bold_clean_box',
    rage_mode: 'rage_mode',
    rage: 'rage_mode',
    ice_pop: 'ice_pop',
    ice: 'ice_pop',
    retro_wave: 'retro_wave',
    retro: 'retro_wave',
    glitch_pop: 'glitch_pop',
    glitch: 'glitch_pop',
    cinema_punch: 'cinema_punch',
    cinema: 'cinema_punch',
    shadow_strike: 'cinema_punch',
    opus_pop: 'mrbeast_animated',
    opus: 'mrbeast_animated',
    capcut_kinetic: 'rage_mode',
    capcut: 'rage_mode',
    high_energy_neon: 'neon_glow',
    minimal_bold: 'basic_clean'
  }
  if (aliases[compact]) return aliases[compact]
  const normalizedSubtitle = normalizeSubtitlePreset(token)
  if (normalizedSubtitle && VERTICAL_CAPTION_PRESETS.includes(normalizedSubtitle as VerticalCaptionPreset)) {
    return normalizedSubtitle as VerticalCaptionPreset
  }
  return null
}

const parseVerticalCaptionFontSize = (value: any): number | null => {
  const parsed = Number(value)
  if (!Number.isFinite(parsed)) return null
  return Math.round(clamp(parsed, VERTICAL_CAPTION_FONT_SIZE_MIN, VERTICAL_CAPTION_FONT_SIZE_MAX))
}

const parseVerticalCaptionFontId = (value: any): SubtitleFontId | null => {
  const normalized = String(value ?? '').trim().toLowerCase()
  if (!normalized) return null
  if (VERTICAL_CAPTION_FONT_IDS.includes(normalized as SubtitleFontId)) return normalized as SubtitleFontId
  return null
}

const parseVerticalCaptionHexColor = (value: any): string | null => {
  const normalized = String(value ?? '').trim().replace(/^#/, '').toUpperCase()
  if (!/^[0-9A-F]{6}$/.test(normalized)) return null
  return normalized
}

const parseVerticalCaptionOutlineWidth = (value: any): number | null => {
  const parsed = Number(value)
  if (!Number.isFinite(parsed)) return null
  return Math.round(clamp(parsed, VERTICAL_CAPTION_OUTLINE_WIDTH_MIN, VERTICAL_CAPTION_OUTLINE_WIDTH_MAX))
}

const parseVerticalCaptionShadowBlur = (value: any): number | null => {
  const parsed = Number(value)
  if (!Number.isFinite(parsed)) return null
  const normalized = parsed > VERTICAL_CAPTION_SHADOW_BLUR_MAX && parsed <= 100
    ? (parsed / 100) * VERTICAL_CAPTION_SHADOW_BLUR_MAX
    : parsed
  return Math.round(clamp(normalized, VERTICAL_CAPTION_SHADOW_BLUR_MIN, VERTICAL_CAPTION_SHADOW_BLUR_MAX))
}

const parseVerticalCaptionPosition = (value: any): number | null => {
  const parsed = Number(value)
  if (!Number.isFinite(parsed)) return null
  return Number(clamp(parsed, 0.02, 0.98).toFixed(4))
}

const parseVerticalCaptionAnimationEnabled = (value: any): boolean | null => {
  if (typeof value === 'boolean') return value
  const normalized = String(value ?? '').trim().toLowerCase()
  if (!normalized) return null
  if (['1', 'true', 'yes', 'on', 'enabled', 'enable', 'animated', 'animate', 'pop', 'slide', 'fade', 'bounce', 'glitch', 'auto'].includes(normalized)) {
    return true
  }
  if (['0', 'false', 'no', 'off', 'disabled', 'disable', 'none', 'static', 'still'].includes(normalized)) {
    return false
  }
  return null
}

const parseVerticalCaptionAnimationMode = (value: any): VerticalClipCaptionAnimation | null => {
  const normalized = String(value ?? '').trim().toLowerCase()
  if (!normalized) return null
  if (['none', 'off', 'disabled', 'static', 'still'].includes(normalized)) return 'none'
  if (['pop', 'pulse', 'punch'].includes(normalized)) return 'pop'
  if (['slide', 'swipe'].includes(normalized)) return 'slide'
  if (['fade', 'dissolve'].includes(normalized)) return 'fade'
  if (['bounce', 'spring'].includes(normalized)) return 'bounce'
  if (['glitch', 'jitter'].includes(normalized)) return 'glitch'
  return null
}

const parseVerticalCaptionAnimationSpeed = (value: any): number | null => {
  const parsed = Number(value)
  if (!Number.isFinite(parsed)) return null
  return Number(clamp(parsed, 0.5, 2.2).toFixed(2))
}

const parseVerticalCaptionDynamicMode = (value: any): VerticalCaptionDynamicMode | null => {
  const normalized = String(value ?? '').trim().toLowerCase()
  if (!normalized) return null
  if (['classic', 'standard', 'default', 'line'].includes(normalized)) return 'classic'
  if (['karaoke_word', 'karaoke', 'word_highlight', 'word-highlight', 'word'].includes(normalized)) return 'karaoke_word'
  if (['kinetic_word', 'kinetic', 'dynamic', 'rapid', 'tiktok'].includes(normalized)) return 'kinetic_word'
  return null
}

const parseVerticalVoicePreset = (value: any): VerticalVoicePreset | null => {
  const normalized = String(value ?? '').trim().toLowerCase()
  if (!normalized) return null
  if (['none', 'off', 'disable', 'disabled', 'normal', 'clean'].includes(normalized)) return 'none'
  if (['deep', 'low', 'bass', 'baritone'].includes(normalized)) return 'deep'
  if (['helium', 'high', 'chipmunk'].includes(normalized)) return 'helium'
  if (['radio', 'walkie', 'walkie-talkie', 'broadcast'].includes(normalized)) return 'radio'
  if (['robot', 'ai', 'synth', 'synthetic'].includes(normalized)) return 'robot'
  return null
}

