router.post('/:id/player-events', async (req: any, res) => {
  try {
    const id = String(req.params.id || '').trim()
    const job = await prisma.job.findUnique({ where: { id } })
    if (!job || job.userId !== req.user.id) return res.status(404).json({ error: 'not_found' })

    const events = parsePlayerTelemetryEventsPayload(req.body || {}, id)
    if (!events.length) {
      return res.status(400).json({ error: 'invalid_player_events' })
    }
    for (const event of events) {
      try {
        await prisma.siteAnalyticsEvent.create({
          data: {
            userId: req.user.id,
            sessionId: event.session_id,
            eventName: `player_${event.event}`,
            category: 'feedback',
            pagePath: '/editor/player',
            retentionProfile: String((job.renderSettings as any)?.retentionStrategyProfile || ''),
            targetPlatform: String((job.renderSettings as any)?.retentionTargetPlatform || ''),
            captionStyle: String((job.renderSettings as any)?.subtitleStyle || ''),
            jobId: id,
            metadata: event
          }
        })
      } catch (error) {
        console.warn('player telemetry analytics write failed', error)
      }
    }
    const analysis = (job.analysis as any) || {}
    const existingEvents = Array.isArray(analysis.player_telemetry_events)
      ? analysis.player_telemetry_events
      : []
    const mergedEvents = [
      ...existingEvents.slice(-2800),
      ...events
    ]
    const sessions = aggregatePlayerTelemetrySessions(mergedEvents as PlayerTelemetryEvent[])
    const summary = summarizePlayerTelemetry(sessions)
    const hookHoldRate = sessions.length
      ? sessions.filter((session) => session.firstDropoffSecond === null || session.firstDropoffSecond >= 8).length / sessions.length
      : null
    const rewatchRate = sessions.length
      ? sessions.filter((session) => session.rewatchHotspots.length > 0).length / sessions.length
      : null
    const derivedFeedback = parseRetentionFeedbackPayload({
      watchPercent: summary.effective_watch_ratio,
      completionPercent: summary.completion_rate,
      hookHoldPercent: hookHoldRate,
      rewatchRate,
      avgViewDurationSec: summary.avg_watch_time,
      source: 'player_telemetry',
      sourceType: 'internal',
      notes: 'Derived from player telemetry events.'
    })
    if (derivedFeedback) {
      await persistRetentionFeedbackForJob({
        job,
        feedback: derivedFeedback,
        analysisPatch: {
          player_telemetry_events: mergedEvents.slice(-3000),
          player_playback_sessions: sessions.slice(-300),
          player_watch_labels: summary,
          player_telemetry_updated_at: toIsoNow()
        }
      })
      await upsertCreatorStyleProfileFromFeedback({
        userId: job.userId,
        feedback: derivedFeedback
      }).catch((error) => {
        console.warn('creator style profile update failed after player telemetry', error)
      })
      await registerPolicyOutcomeForJob({
        userId: job.userId,
        jobId: id,
        feedback: derivedFeedback,
        source: 'player_telemetry',
        isPlatform: false,
        metadata: {
          route: 'jobs/:id/player-events',
          sessionCount: sessions.length
        }
      }).catch((error) => {
        console.warn('policy outcome registration failed after player telemetry', error)
      })
      const durationForReward = Number(job.inputDurationSeconds || 0)
      if (Number.isFinite(durationForReward) && durationForReward > 0.1) {
        const rewardSignal = derivePerSecondRewardSignal({
          durationSeconds: durationForReward,
          retentionPoints: [
            { timestamp: 0, watchedPct: Number((summary.completion_rate ?? summary.effective_watch_ratio ?? 0) * 100) },
            { timestamp: durationForReward * 0.35, watchedPct: Number((summary.effective_watch_ratio ?? 0) * 100) },
            { timestamp: durationForReward * 0.98, watchedPct: Number((summary.completion_rate ?? 0) * 100) }
          ],
          skipHotspots: Array.isArray(summary.skip_hotspots) ? summary.skip_hotspots : [],
          rewatchHotspots: Array.isArray(summary.rewatch_hotspots) ? summary.rewatch_hotspots : []
        })
        await ingestPlatformRewardSignal({
          userId: job.userId,
          jobId: id,
          source: 'player_telemetry',
          videoId: null,
          perSecondRewards: rewardSignal.perSecondRewards,
          summary: {
            ...rewardSignal.summary,
            sessionCount: sessions.length,
            sourceRoute: 'jobs/:id/player-events'
          }
        }).catch((error) => {
          console.warn('platform reward ingest failed after player telemetry', error)
        })
      }
      try {
        await runFeedbackLoop({
          trigger: 'feedback_submission',
          actorUserId: req.user?.id || null
        })
      } catch (error) {
        console.warn('feedback loop run failed after player telemetry', error)
      }
      runBackgroundLearningCycleForJob(job.userId, id, 'player_telemetry')
      return res.json({
        ok: true,
        ingested: events.length,
        summary,
        feedback: derivedFeedback
      })
    }
    await updateJob(job.id, {
      analysis: {
        ...analysis,
        player_telemetry_events: mergedEvents.slice(-3000),
        player_playback_sessions: sessions.slice(-300),
        player_watch_labels: summary,
        player_telemetry_updated_at: toIsoNow()
      }
    })
    return res.json({
      ok: true,
      ingested: events.length,
      summary
    })
  } catch (err) {
    console.error('player telemetry ingest failed', err)
    return res.status(500).json({ error: 'server_error' })
  }
})

router.post('/:id/editor-taste-feedback', async (req: any, res) => {
  try {
    const id = String(req.params.id || '').trim()
    const job = await prisma.job.findUnique({ where: { id } })
    if (!job || job.userId !== req.user.id) return res.status(404).json({ error: 'not_found' })
    if (job.status !== 'completed') return res.status(403).json({ error: 'not_ready' })
    const wouldPublishAsIs = Boolean(req.body?.wouldPublishAsIs ?? req.body?.would_publish_as_is)
    const hookStrength = Number(clamp(Number(req.body?.hookStrength ?? req.body?.hook_strength), 1, 10))
    const pacingFeel = Number(clamp(Number(req.body?.pacingFeel ?? req.body?.pacing_feel), 1, 10))
    const bingeContinuity = Number(clamp(Number(req.body?.bingeContinuity ?? req.body?.binge_continuity), 1, 10))
    if (!Number.isFinite(hookStrength) || !Number.isFinite(pacingFeel) || !Number.isFinite(bingeContinuity)) {
      return res.status(400).json({ error: 'invalid_editor_taste_feedback' })
    }
    const notes = typeof req.body?.notes === 'string' && req.body.notes.trim()
      ? req.body.notes.trim().slice(0, 400)
      : null
    const payload: EditorTasteFeedbackPayload = {
      wouldPublishAsIs,
      hookStrength: Number(hookStrength.toFixed(2)),
      pacingFeel: Number(pacingFeel.toFixed(2)),
      bingeContinuity: Number(bingeContinuity.toFixed(2)),
      notes,
      submittedAt: toIsoNow()
    }
    const analysis = (job.analysis as any) || {}
    const history = Array.isArray(analysis.editor_taste_feedback_history)
      ? analysis.editor_taste_feedback_history.slice(-59)
      : []
    const manualScore = Number(clamp(
      0.38 * payload.hookStrength * 10 +
      0.3 * payload.pacingFeel * 10 +
      0.32 * payload.bingeContinuity * 10 +
      (payload.wouldPublishAsIs ? 6 : -6),
      0,
      100
    ).toFixed(2))
    const mappedFeedback = parseRetentionFeedbackPayload({
      manualScore,
      hookHoldPercent: payload.hookStrength / 10,
      watchPercent: payload.bingeContinuity / 10,
      completionPercent: payload.pacingFeel / 10,
      source: 'editor_taste_review',
      sourceType: 'internal',
      notes: payload.notes
    })
    if (!mappedFeedback) return res.status(400).json({ error: 'invalid_editor_taste_feedback' })
    await persistRetentionFeedbackForJob({
      job,
      feedback: mappedFeedback,
      analysisPatch: {
        editor_taste_feedback: payload,
        editor_taste_feedback_history: [...history, payload],
        editor_taste_feedback_updated_at: toIsoNow()
      }
    })
    await upsertCreatorStyleProfileFromFeedback({
      userId: job.userId,
      feedback: {
        ...mappedFeedback,
        source: 'editor_taste_review'
      }
    }).catch((error) => {
      console.warn('creator style profile update failed after editor taste feedback', error)
    })
    await registerPolicyOutcomeForJob({
      userId: job.userId,
      jobId: id,
      feedback: mappedFeedback,
      source: 'editor_taste_feedback',
      isPlatform: false,
      metadata: {
        route: 'jobs/:id/editor-taste-feedback',
        wouldPublishAsIs: payload.wouldPublishAsIs
      }
    }).catch((error) => {
      console.warn('policy outcome registration failed after editor taste feedback', error)
    })
    try {
      await prisma.siteAnalyticsEvent.create({
        data: {
          userId: req.user.id,
          sessionId: null,
          eventName: 'editor_taste_feedback',
          category: 'feedback',
          pagePath: '/editor',
          retentionProfile: String((job.renderSettings as any)?.retentionStrategyProfile || ''),
          targetPlatform: String((job.renderSettings as any)?.retentionTargetPlatform || ''),
          captionStyle: String((job.renderSettings as any)?.subtitleStyle || ''),
          jobId: id,
          metadata: payload
        }
      })
    } catch (error) {
      console.warn('editor taste analytics write failed', error)
    }
    try {
      await runFeedbackLoop({
        trigger: 'creator_feedback_submission',
        actorUserId: req.user?.id || null
      })
    } catch (error) {
      console.warn('feedback loop run failed after editor taste feedback', error)
    }
    const learning = await runForegroundLearningCycleForJob(job.userId, id, 'editor_taste_feedback')
    return res.json({
      ok: true,
      feedback: payload,
      mappedRetentionFeedback: mappedFeedback,
      learning
    })
  } catch (err) {
    console.error('editor taste feedback failed', err)
    return res.status(500).json({ error: 'server_error' })
  }
})

router.get('/:id/output-url', async (req: any, res) => {
  try {
    const id = req.params.id
    const job = await prisma.job.findUnique({ where: { id } })
    if (!job || job.userId !== req.user.id) return res.status(404).json({ error: 'not_found' })
    const outputPaths = getOutputPathsForJob(job)
    if (!outputPaths.length) return res.status(404).json({ error: 'not_found' })
    const requestedClip = Number.parseInt(String(req.query?.clip ?? '1'), 10)
    const clipIndex = Number.isFinite(requestedClip) ? clamp(requestedClip - 1, 0, outputPaths.length - 1) : 0
    const selectedOutputPath = outputPaths[clipIndex]
    try {
      const resolved = await resolveOutputUrlWithLocalFallback({
        req,
        job,
        outputPath: selectedOutputPath,
        clipIndex
      })

      scheduleOutputAutoDeleteIfEnabled({
        requestId: req.requestId,
        jobId: id,
        outputPaths,
        selectedOutputPath,
        source: resolved.source
      })

      res.json({ url: resolved.url, source: resolved.source })
    } catch (err) {
      res.status(500).json({ error: 'signed_url_failed' })
    }
  } catch (err) {
    res.status(500).json({ error: 'server_error' })
  }
})

// Stream local output file when remote output storage/signing is unavailable.
router.get('/:id/local-output', async (req: any, res) => {
  try {
    const id = req.params.id
    const job = await prisma.job.findUnique({ where: { id } })
    if (!job || job.userId !== req.user.id) return res.status(404).json({ error: 'not_found' })
    if (job.status !== 'completed') return res.status(403).json({ error: 'not_ready' })
    const outputPaths = getOutputPathsForJob(job)
    if (!outputPaths.length) return res.status(404).json({ error: 'not_found' })
    const requestedClip = Number.parseInt(String(req.query?.clip ?? '1'), 10)
    const clipIndex = Number.isFinite(requestedClip) ? clamp(requestedClip - 1, 0, outputPaths.length - 1) : 0
    const localOutput = getLocalOutputFileInfo(job, clipIndex)
    if (!localOutput) return res.status(404).json({ error: 'local_output_not_found' })

    const fileSize = localOutput.size
    const rangeHeader = String(req.headers?.range || '').trim()
    const rangeMatch = /^bytes=(\d*)-(\d*)$/i.exec(rangeHeader)
    const fileName = path.basename(outputPaths[clipIndex] || localOutput.filePath)
    const wantsDownload = String(req.query?.download || '').toLowerCase() === '1' || String(req.query?.download || '').toLowerCase() === 'true'
    res.setHeader('Cache-Control', 'no-store, no-cache, must-revalidate, proxy-revalidate, max-age=0')
    res.setHeader('Pragma', 'no-cache')
    res.setHeader('Expires', '0')
    res.setHeader('Surrogate-Control', 'no-store')
    res.setHeader('Content-Type', 'video/mp4')
    res.setHeader('Accept-Ranges', 'bytes')
    if (wantsDownload) {
      res.setHeader('Content-Disposition', `attachment; filename="${fileName}"`)
    }

    if (rangeMatch) {
      const rawStart = rangeMatch[1] ? Number.parseInt(rangeMatch[1], 10) : 0
      const rawEnd = rangeMatch[2] ? Number.parseInt(rangeMatch[2], 10) : fileSize - 1
      const start = clamp(Number.isFinite(rawStart) ? rawStart : 0, 0, Math.max(0, fileSize - 1))
      const end = clamp(Number.isFinite(rawEnd) ? rawEnd : fileSize - 1, start, Math.max(start, fileSize - 1))
      if (start >= fileSize || end >= fileSize || start > end) {
        res.setHeader('Content-Range', `bytes */${fileSize}`)
        return res.status(416).end()
      }
      const chunkSize = end - start + 1
      res.status(206)
      res.setHeader('Content-Range', `bytes ${start}-${end}/${fileSize}`)
      res.setHeader('Content-Length', chunkSize)
      const stream = fs.createReadStream(localOutput.filePath, { start, end })
      stream.on('error', () => res.status(500).end())
      stream.pipe(res)
      return
    }

    res.setHeader('Content-Length', fileSize)
    const stream = fs.createReadStream(localOutput.filePath)
    stream.on('error', () => res.status(500).end())
    stream.pipe(res)
  } catch (err) {
    res.status(500).json({ error: 'server_error' })
  }
})

const buildUniquenessSignatureForTest = ({
  strategyProfile,
  targetPlatform,
  editorMode,
  maxCuts,
  longFormAggression,
  longFormClarityVsSpeed,
  tangentKiller,
  durationSeconds = 300
}: {
  strategyProfile?: RetentionStrategyProfile | string | null
  targetPlatform?: RetentionTargetPlatform | string | null
  editorMode?: EditorModeSelection | string | null
  maxCuts?: number | null
  longFormAggression?: number | null
  longFormClarityVsSpeed?: number | null
  tangentKiller?: boolean | null
  durationSeconds?: number | null
}) => {
  const resolvedStrategy = parseRetentionStrategyProfile(strategyProfile)
  const resolvedTargetPlatform = parseRetentionTargetPlatform(targetPlatform || 'auto')
  const resolvedEditorMode = parseEditorModeSelection(editorMode) || 'auto'
  const resolvedMaxCuts = parseMaxCutsPreference(maxCuts) ?? 8
  const resolvedLongFormAggression = parseLongFormAggression(longFormAggression) ?? DEFAULT_EDIT_OPTIONS.longFormAggression
  const resolvedLongFormClarity = parseLongFormClarityVsSpeed(longFormClarityVsSpeed) ?? DEFAULT_EDIT_OPTIONS.longFormClarityVsSpeed
  const resolvedTangentKiller = typeof tangentKiller === 'boolean' ? tangentKiller : DEFAULT_EDIT_OPTIONS.tangentKiller
  const resolvedDuration = Math.max(60, Number.isFinite(Number(durationSeconds)) ? Number(durationSeconds) : 300)
  const resolvedAggressionLevel = STRATEGY_TO_AGGRESSION[resolvedStrategy] || 'medium'

  const fallbackMode = resolvedEditorMode !== 'auto' ? resolvedEditorMode : null
  const styleProfile: ContentStyleProfile | null = fallbackMode
    ? {
        style: EDITOR_MODE_TO_STYLE[fallbackMode],
        confidence: 1,
        rationale: ['Synthetic uniqueness benchmark mode override.'],
        tempoBias: 0,
        interruptBias: 0,
        hookBias: 0
      }
    : null
  const nicheProfile: VideoNicheProfile | null = fallbackMode
    ? {
        niche: EDITOR_MODE_TO_NICHE[fallbackMode],
        confidence: 1,
        rationale: ['Synthetic uniqueness benchmark mode override.'],
        styleAlignment: EDITOR_MODE_TO_STYLE[fallbackMode],
        metrics: {
          avgSpeech: 0.54,
          avgScene: 0.42,
          avgEmotion: 0.5,
          spikeRatio: 0.36,
          transcriptCueCount: 18,
          durationSeconds: resolvedDuration
        }
      }
    : null

  const syntheticWindows: EngagementWindow[] = [
    {
      time: 6,
      audioEnergy: 0.44,
      speechIntensity: 0.58,
      motionScore: 0.41,
      facePresence: 0.52,
      textDensity: 0.18,
      sceneChangeRate: 0.32,
      emotionalSpike: 0,
      vocalExcitement: 0.46,
      emotionIntensity: 0.5,
      audioVariance: 0.34,
      keywordIntensity: 0.4,
      curiosityTrigger: 0.32,
      fillerDensity: 0.08,
      boredomScore: 0.24,
      hookScore: 0.56,
      narrativeProgress: 0.26,
      score: 0.52
    },
    {
      time: 18,
      audioEnergy: 0.62,
      speechIntensity: 0.7,
      motionScore: 0.54,
      facePresence: 0.58,
      textDensity: 0.2,
      sceneChangeRate: 0.46,
      emotionalSpike: 1,
      vocalExcitement: 0.64,
      emotionIntensity: 0.68,
      audioVariance: 0.46,
      keywordIntensity: 0.56,
      curiosityTrigger: 0.48,
      fillerDensity: 0.06,
      boredomScore: 0.16,
      hookScore: 0.72,
      narrativeProgress: 0.5,
      score: 0.69
    },
    {
      time: 30,
      audioEnergy: 0.38,
      speechIntensity: 0.52,
      motionScore: 0.34,
      facePresence: 0.5,
      textDensity: 0.16,
      sceneChangeRate: 0.28,
      emotionalSpike: 0,
      vocalExcitement: 0.4,
      emotionIntensity: 0.43,
      audioVariance: 0.3,
      keywordIntensity: 0.28,
      curiosityTrigger: 0.24,
      fillerDensity: 0.1,
      boredomScore: 0.28,
      hookScore: 0.44,
      narrativeProgress: 0.72,
      score: 0.46
    }
  ]
  const tunedSegments = applyDurationBandSpeedTuning({
    segments: [
      { start: 0, end: 10, speed: 1.04 },
      { start: 10, end: 20, speed: 1.02 },
      { start: 20, end: 32, speed: 1.01 }
    ],
    windows: syntheticWindows,
    durationSeconds: resolvedDuration,
    editorMode: resolvedEditorMode
  })
  const avgSpeed = tunedSegments.length
    ? tunedSegments.reduce((sum, segment) => sum + Number(segment.speed || 1), 0) / tunedSegments.length
    : 1

  const interruptRange = resolveInterruptIntervalRange({
    strategyProfile: resolvedStrategy,
    editorMode: resolvedEditorMode,
    styleProfile
  })
  const verticalInterruptTarget = getVerticalInterruptTargetIntervalSeconds({
    platformProfile: parsePlatformProfile(resolvedTargetPlatform, 'auto'),
    strategyProfile: resolvedStrategy,
    editorMode: resolvedEditorMode,
    styleProfile
  })
  const clipCandidateTarget = resolveClipCandidateTarget({
    durationSeconds: resolvedDuration,
    editorMode: resolvedEditorMode,
    nicheProfile
  })
  const clipExportTarget = resolveAutoExportClipTarget({
    durationSeconds: resolvedDuration,
    editorMode: resolvedEditorMode,
    nicheProfile
  })
  const contentFormat: RetentionContentFormat = resolvedEditorMode === 'podcast'
    ? 'podcast_clip'
    : resolvedTargetPlatform === 'tiktok' || resolvedTargetPlatform === 'instagram_reels'
      ? 'tiktok_short'
      : 'youtube_long'
  const modeRetentionTargets = resolveModeRetentionTargets(resolvedEditorMode)
  const qualityThresholds = resolveQualityGateThresholds({
    aggressionLevel: resolvedAggressionLevel,
    hasTranscript: true,
    signalStrength: 0.64,
    contentFormat,
    targetPlatform: resolvedTargetPlatform,
    retentionTargetScore: modeRetentionTargets.target
  })
  const modeBias = getVerticalModeScoreBias(resolvedEditorMode)
  const maxCutsPerTen = getMaxCutsPer10Seconds({
    renderMode: 'horizontal',
    targetPlatform: resolvedTargetPlatform
  })
  const hardCutBudget = Math.max(1, Math.floor((resolvedDuration / 10) * maxCutsPerTen))
  const effectiveCuts = Math.min(hardCutBudget, resolvedMaxCuts)
  const longFormPreset = resolveLongFormPresetByAggression(resolvedLongFormAggression)

  return JSON.stringify({
    strategy: resolvedStrategy,
    targetPlatform: resolvedTargetPlatform,
    editorMode: resolvedEditorMode,
    mappedStyle: styleProfile?.style || null,
    mappedNiche: nicheProfile?.niche || null,
    maxCuts: resolvedMaxCuts,
    effectiveCuts,
    hardCutBudget,
    longFormPreset,
    longFormAggression: resolvedLongFormAggression,
    longFormClarityVsSpeed: resolvedLongFormClarity,
    tangentKiller: resolvedTangentKiller,
    interval: interruptRange,
    verticalInterruptTarget,
    clipCandidateTarget,
    clipExportTarget,
    qualityThresholds,
    modeRetentionTargets,
    modeBias,
    avgSpeed: Number(avgSpeed.toFixed(4))
  })
}

const buildEditPlanForTest = async ({
  filePath,
  aggressionLevel,
  strategyProfile,
  editorMode,
  longFormPreset,
  longFormAggression,
  longFormClarityVsSpeed,
  maxCuts,
  tangentKiller,
  autoTranscribe,
  transcriptSrtPath,
  transcriptCues
}: {
  filePath: string
  aggressionLevel?: RetentionAggressionLevel | string
  strategyProfile?: RetentionStrategyProfile | string
  editorMode?: EditorModeSelection | string | null
  longFormPreset?: LongFormPreset | string | null
  longFormAggression?: number | string | null
  longFormClarityVsSpeed?: number | string | null
  maxCuts?: number | string | null
  tangentKiller?: boolean | null
  autoTranscribe?: boolean | null
  transcriptSrtPath?: string | null
  transcriptCues?: TranscriptCue[] | null
}) => {
  const absolutePath = path.resolve(String(filePath || ''))
  if (!absolutePath || !fs.existsSync(absolutePath)) {
    throw new Error(`test_input_missing:${absolutePath}`)
  }
  const durationSeconds = getDurationSeconds(absolutePath)
  if (!durationSeconds || !Number.isFinite(durationSeconds) || durationSeconds <= 0) {
    throw new Error(`test_input_duration_unavailable:${absolutePath}`)
  }
  const normalizedAggression = parseRetentionAggressionLevel(aggressionLevel)
  const normalizedStrategy = parseRetentionStrategyProfile(
    strategyProfile || strategyFromAggressionLevel(normalizedAggression)
  )
  const normalizedEditorMode = parseEditorModeSelection(editorMode)
  const normalizedLongFormPreset = (
    longFormPreset === undefined || longFormPreset === null || longFormPreset === ''
      ? null
      : parseLongFormPreset(longFormPreset)
  )
  const maxCutsRaw = Number(maxCuts)
  const normalizedMaxCuts = Number.isFinite(maxCutsRaw)
    ? Math.round(clamp(maxCutsRaw, USER_MAX_CUTS_MIN, USER_MAX_CUTS_MAX))
    : null
  const normalizedLongFormAggression = parseLongFormAggression(longFormAggression)
  const normalizedLongFormClarity = parseLongFormClarityVsSpeed(longFormClarityVsSpeed)
  const options: EditOptions = {
    ...DEFAULT_EDIT_OPTIONS,
    retentionAggressionLevel: normalizedAggression,
    retentionStrategyProfile: normalizedStrategy,
    aggressiveMode: isAggressiveRetentionLevel(normalizedAggression),
    ...(normalizedEditorMode === null ? {} : { editorMode: normalizedEditorMode }),
    ...(normalizedLongFormPreset ? { longFormPreset: normalizedLongFormPreset } : {}),
    ...(normalizedLongFormAggression === null ? {} : { longFormAggression: normalizedLongFormAggression }),
    ...(normalizedLongFormClarity === null ? {} : { longFormClarityVsSpeed: normalizedLongFormClarity }),
    ...(normalizedMaxCuts === null ? {} : { maxCutsRequested: normalizedMaxCuts }),
    ...(typeof tangentKiller === 'boolean' ? { tangentKiller } : {})
  }
  let normalizedTranscriptCues: TranscriptCue[] = Array.isArray(transcriptCues)
    ? transcriptCues
        .map((cue) => normalizeTranscriptCue(cue))
        .filter((cue): cue is TranscriptCue => Boolean(cue))
    : []
  if (!normalizedTranscriptCues.length && transcriptSrtPath) {
    const absoluteSrt = path.resolve(String(transcriptSrtPath))
    normalizedTranscriptCues = parseTranscriptCues(absoluteSrt)
  }
  const shouldAutoTranscribe = autoTranscribe === true
  if (!normalizedTranscriptCues.length && shouldAutoTranscribe) {
    const transcriptWorkDir = fs.mkdtempSync(path.join(os.tmpdir(), 'retention-test-transcribe-'))
    try {
      const absoluteStats = fs.statSync(absolutePath)
      const generatedSrt = await generateSubtitles(absolutePath, transcriptWorkDir, {
        durationSeconds,
        renderMode: 'horizontal',
        fastMode: options.fastMode,
        purpose: 'test',
        inputBytes: absoluteStats.size
      })
      if (generatedSrt) {
        normalizedTranscriptCues = parseTranscriptCues(generatedSrt)
      }
    } catch {
      normalizedTranscriptCues = []
    } finally {
      try {
        fs.rmSync(transcriptWorkDir, { recursive: true, force: true })
      } catch {
        // ignore cleanup failures in test path
      }
    }
  }
  const plan = await buildEditPlan(absolutePath, durationSeconds, options, undefined, {
    aggressionLevel: normalizedAggression,
    transcriptCues: normalizedTranscriptCues
  })
  if (Array.isArray(plan?.segments) && plan.segments.length) {
    plan.segments = stabilizeStoryPacingSegments({
      segments: plan.segments,
      windows: Array.isArray(plan?.engagementWindows) ? plan.engagementWindows : [],
      styleProfile: plan?.styleProfile ?? null
    })
  }
  const candidatePool: HookCandidate[] = (
    Array.isArray(plan?.hookCandidates) && plan.hookCandidates.length
      ? plan.hookCandidates
      : plan?.hook
        ? [plan.hook]
        : []
  ).filter((candidate): candidate is HookCandidate => Boolean(candidate))
  const planWindows = Array.isArray(plan?.engagementWindows) ? plan.engagementWindows : []
  const planSegments = Array.isArray(plan?.segments) ? plan.segments : []
  const planSilences = Array.isArray(plan?.silences) ? plan.silences : []
  const hasTranscriptSignals = normalizedTranscriptCues.length > 0
  const signalStrength = computeContentSignalStrength(planWindows)
  const hookDecision = selectAuthoritativeAutoHookDecision({
    candidates: candidatePool,
    aggressionLevel: normalizedAggression,
    hasTranscript: hasTranscriptSignals,
    signalStrength,
    windows: planWindows,
    transcriptCues: normalizedTranscriptCues,
    segments: planSegments,
    silences: planSilences,
    durationSeconds,
    recentHooks: null,
    creativeVariant: options.creativeVariant
  })
  const resolvedHook = hookDecision?.candidate ||
    pickAuditedOpeningCandidateFromPool({
      candidates: candidatePool,
      durationSeconds,
      maxStartSeconds: 45,
      naturalOnly: true
    }) ||
    buildSafeNoHookOpeningCandidate({
      segments: planSegments,
      durationSeconds
    }) ||
    buildFallbackHookCandidateFromStorySegments({
      segments: planSegments,
      windows: planWindows,
      silences: planSilences,
      durationSeconds
    })
  if (resolvedHook) {
    const enforcedHook = enforceAutoHookDurationRange({
      candidate: resolvedHook,
      durationSeconds
    })
    const lockedDuration = Number(clamp(
      AUTO_HOOK_DURATION_MAX_SECONDS,
      HOOK_MIN,
      Math.min(HOOK_MAX, durationSeconds)
    ).toFixed(3))
    const maxHookStart = Math.max(0, durationSeconds - lockedDuration)
    plan.hook = {
      ...enforcedHook,
      start: Number(clamp(enforcedHook.start, 0, maxHookStart).toFixed(3)),
      duration: Number(lockedDuration.toFixed(3))
    }
    if (
      Array.isArray(plan.hookCandidates) &&
      !plan.hookCandidates.some((candidate) => (
        Math.abs(candidate.start - plan.hook.start) < 0.01 &&
        Math.abs(candidate.duration - plan.hook.duration) < 0.01
      ))
    ) {
      plan.hookCandidates = [plan.hook, ...plan.hookCandidates].slice(0, Math.max(8, HOOK_SELECTION_MAX_CANDIDATES))
    }
  }
  const runtimeFloorRatioForTest = resolveLongFormMinimumEditedRuntimeRatio({
    durationSeconds,
    aggressiveMode: Boolean(options.aggressiveMode),
    contentFormat: durationSeconds >= LONG_FORM_RUNTIME_FLOOR_MIN_DURATION_SECONDS ? 'youtube_long' : 'tiktok_short',
    longFormAggression: options.longFormAggression ?? null,
    longFormClarityVsSpeed: options.longFormClarityVsSpeed ?? null
  })
  if (runtimeFloorRatioForTest > 0 && Array.isArray(plan?.segments) && plan.segments.length) {
    const currentEditedRuntimeSeconds = computeEditedRuntimeSeconds(plan.segments)
    const minimumEditedRuntimeSeconds = durationSeconds * runtimeFloorRatioForTest
    if (currentEditedRuntimeSeconds + 0.25 < minimumEditedRuntimeSeconds) {
      const conservativeBase = buildGuaranteedFallbackSegments(durationSeconds, {
        ...options,
        aggressiveMode: false,
        onlyCuts: false
      })
      const hookForRuntimeFloor = plan.hook || null
      const timelineWithHook = hookForRuntimeFloor
        ? buildTimelineWithHookAtStartForTest(conservativeBase.map((segment) => ({ ...segment })), hookForRuntimeFloor)
        : conservativeBase.map((segment) => ({ ...segment }))
      const rescuedSegments = prepareSegmentsForRender(timelineWithHook, durationSeconds)
      const stabilizedRescue = stabilizeStoryPacingSegments({
        segments: rescuedSegments,
        windows: planWindows,
        styleProfile: plan?.styleProfile ?? null
      })
      const rescuedEditedRuntimeSeconds = computeEditedRuntimeSeconds(stabilizedRescue)
      if (
        stabilizedRescue.length &&
        rescuedEditedRuntimeSeconds >= minimumEditedRuntimeSeconds &&
        rescuedEditedRuntimeSeconds > currentEditedRuntimeSeconds + 0.5
      ) {
        plan.segments = stabilizedRescue
      }
    }
  }
  return plan
}

